import { useState, useRef, useEffect } from "react";

const GROQ_API_KEY     = "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";
const GROQ_CHAT_URL    = "https://api.groq.com/openai/v1/chat/completions";
const GROQ_STT_URL     = "https://api.groq.com/openai/v1/audio/transcriptions";
const STORAGE_KEY      = "aria_last_conversation";
const SILENCE_MS        = 3000;  // auto-submit after 3s of silence AFTER speech starts
const VOICE_THRESH      = 0.020; // RMS threshold — raised to avoid ambient noise false triggers
const INTERRUPT_THRESH  = 0.045; // RMS to interrupt Aria (high to avoid false triggers)
const SPEAK_COOLDOWN    = 1500;  // ms after Aria starts before interrupt can fire
const INTERRUPT_FRAMES  = 15;    // consecutive frames to interrupt Aria (~250ms)
const START_FRAMES      = 8;     // consecutive frames above VOICE_THRESH to confirm user spoke
const IDLE_FRAMES       = 6;     // consecutive frames above VOICE_THRESH while idle to start recording
const POST_SPEAK_DELAY  = 1100;  // ms after TTS ends before listening — lets echo die down

export default function AudioCallTab({ topic, language }) {
  const [messages,   setMessages]   = useState([]);
  const [loading,    setLoading]    = useState(false);
  const [listening,  setListening]  = useState(false);
  const [callActive, setCallActive] = useState(false);
  const [ariaStatus, setAriaStatus] = useState("idle");
  const [textInput,  setTextInput]  = useState("");
  const [micError,   setMicError]   = useState("");
  const [savedConvo, setSavedConvo] = useState(() => {
    try { return JSON.parse(localStorage.getItem(STORAGE_KEY)) || null; }
    catch { return null; }
  });

  const synthRef          = useRef(window.speechSynthesis);
  const streamRef         = useRef(null);
  const mediaRecRef       = useRef(null);
  const audioChunksRef    = useRef([]);
  const audioCtxRef       = useRef(null);
  const analyserRef       = useRef(null);
  const rafRef            = useRef(null);
  const mimeTypeRef       = useRef("");
  const lastSoundRef      = useRef(Date.now());
  const speakStartRef     = useRef(0);
  const ariaStatusRef     = useRef("idle");
  const listeningRef       = useRef(false);
  const hasSpokenRef       = useRef(false);  // true once sustained user voice confirmed
  const hasSpokenFramesRef = useRef(0);      // consecutive frames above VOICE_THRESH while listening
  const idleCountRef       = useRef(0);      // consecutive frames above VOICE_THRESH while idle
  const interruptCountRef  = useRef(0);      // consecutive frames above INTERRUPT_THRESH while speaking
  const messagesRef        = useRef([]);
  const messagesEndRef     = useRef(null);

  useEffect(() => { messagesRef.current   = messages;   }, [messages]);
  useEffect(() => { ariaStatusRef.current = ariaStatus; }, [ariaStatus]);
  useEffect(() => { listeningRef.current  = listening;  }, [listening]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // On tab switch / unmount: stop everything, save convo
  useEffect(() => {
    return () => {
      cleanupCall();
      const msgs = messagesRef.current;
      if (msgs.length > 0) localStorage.setItem(STORAGE_KEY, JSON.stringify(msgs));
    };
  }, []);

  function getLangCode(code) {
    const map = { es: "es-ES", fr: "fr-FR", de: "de-DE", ja: "ja-JP", pt: "pt-PT" };
    return map[code] || "en-US";
  }

  function cleanupCall() {
    if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
    if (mediaRecRef.current && mediaRecRef.current.state !== "inactive") {
      try { mediaRecRef.current.stop(); } catch (_) {}
    }
    mediaRecRef.current = null;
    if (audioCtxRef.current) { try { audioCtxRef.current.close(); } catch (_) {} audioCtxRef.current = null; }
    analyserRef.current = null;
    if (streamRef.current) { streamRef.current.getTracks().forEach(t => t.stop()); streamRef.current = null; }
    synthRef.current.cancel();
  }

  // ── START CALL ──────────────────────────────────────────────────────────────
  async function startCall(resumedMessages = []) {
    setMicError("");
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true },
      });
      streamRef.current = stream;

      const ctx      = new AudioContext();
      const src      = ctx.createMediaStreamSource(stream);
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 1024;
      src.connect(analyser);
      audioCtxRef.current = ctx;
      analyserRef.current = analyser;

      mimeTypeRef.current = ["audio/webm;codecs=opus", "audio/webm", "audio/ogg"]
        .find(t => MediaRecorder.isTypeSupported(t)) || "";

      setMessages(resumedMessages);
      setCallActive(true);
      ariaStatusRef.current = "idle";
      setAriaStatus("idle");

      startMonitorLoop();

      if (resumedMessages.length === 0) {
        speakAria("Hello! I am Aria. Let us practice " + topic + ". Just start speaking after I finish!");
      } else {
        speakAria("Welcome back! Let us continue our " + topic + " practice.");
      }
    } catch (err) {
      console.error("Mic error:", err);
      setMicError("Microphone access denied. Please allow microphone permission and try again.");
    }
  }

  // ── MONITOR LOOP: runs every animation frame ─────────────────────────────
  function startMonitorLoop() {
    const analyser = analyserRef.current;
    if (!analyser) return;
    const data = new Uint8Array(analyser.frequencyBinCount);
    lastSoundRef.current = Date.now();

    function tick() {
      if (!analyserRef.current) return; // call ended

      analyser.getByteTimeDomainData(data);
      let sum = 0;
      for (let i = 0; i < data.length; i++) {
        const v = (data[i] - 128) / 128;
        sum += v * v;
      }
      const rms    = Math.sqrt(sum / data.length);
      const status = ariaStatusRef.current;

      // LISTENING: only count silence AFTER user has actually spoken (sustained voice required)
      if (status === "listening" && listeningRef.current) {
        if (rms > VOICE_THRESH) {
          hasSpokenFramesRef.current++;
          if (hasSpokenFramesRef.current >= START_FRAMES) {
            hasSpokenRef.current = true;       // confirmed — user is genuinely speaking
          }
          lastSoundRef.current = Date.now();   // keep resetting silence timer while voice active
        } else {
          hasSpokenFramesRef.current = 0;      // reset frame counter on any quiet frame
          if (hasSpokenRef.current) {
            // Submit only after SILENCE_MS of quiet, and only if user actually spoke
            if (Date.now() - lastSoundRef.current >= SILENCE_MS) {
              if (mediaRecRef.current && mediaRecRef.current.state === "recording") {
                ariaStatusRef.current = "thinking";
                listeningRef.current  = false;
                mediaRecRef.current.stop();
              }
            }
          }
        }
        // If hasSpokenRef is still false: keep waiting indefinitely — don't auto-stop

      // IDLE: require sustained voice (IDLE_FRAMES) before starting recording — debounce noise spikes
      } else if (status === "idle" && !listeningRef.current) {
        if (rms > VOICE_THRESH) {
          idleCountRef.current++;
          if (idleCountRef.current >= IDLE_FRAMES) {
            idleCountRef.current = 0;
            beginRecording();
          }
        } else {
          idleCountRef.current = 0; // reset on any quiet frame
        }

      // SPEAKING: only interrupt if user sustains voice for INTERRUPT_FRAMES consecutive frames
      } else if (status === "speaking") {
        const age = Date.now() - speakStartRef.current;
        if (age > SPEAK_COOLDOWN && rms > INTERRUPT_THRESH) {
          interruptCountRef.current++;
          if (interruptCountRef.current >= INTERRUPT_FRAMES) {
            interruptCountRef.current = 0;
            ariaStatusRef.current = "listening";
            synthRef.current.cancel();
            setTimeout(() => beginRecording(), 80);
          }
        } else {
          interruptCountRef.current = 0; // reset if voice drops
        }
      }

      rafRef.current = requestAnimationFrame(tick);
    }

    rafRef.current = requestAnimationFrame(tick);
  }

  // ── BEGIN RECORDING ────────────────────────────────────────────────────────
  function beginRecording() {
    if (!streamRef.current)                   return;
    if (listeningRef.current)                 return;
    if (ariaStatusRef.current === "thinking") return;
    if (ariaStatusRef.current === "speaking") return;

    listeningRef.current       = true;
    ariaStatusRef.current      = "listening";
    hasSpokenRef.current       = false;  // reset: wait for sustained speech before silence timer
    hasSpokenFramesRef.current = 0;      // reset frame counter
    idleCountRef.current       = 0;      // reset idle debounce
    interruptCountRef.current  = 0;

    try {
      const mimeType = mimeTypeRef.current;
      const recorder = new MediaRecorder(
        streamRef.current,
        mimeType ? { mimeType } : undefined
      );
      audioChunksRef.current = [];
      mediaRecRef.current    = recorder;
      lastSoundRef.current   = Date.now();

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        setListening(false);
        const chunks = audioChunksRef.current;
        audioChunksRef.current = [];

        if (!chunks.length || !streamRef.current) {
          ariaStatusRef.current = "idle"; setAriaStatus("idle"); return;
        }
        const blob = new Blob(chunks, { type: mimeType || "audio/webm" });
        if (blob.size < 500) {
          ariaStatusRef.current = "idle"; setAriaStatus("idle"); return;
        }

        ariaStatusRef.current = "thinking";
        setAriaStatus("thinking");

        try {
          const ext      = (mimeType || "audio/webm").includes("ogg") ? "ogg" : "webm";
          const formData = new FormData();
          formData.append("file",     blob,              "rec." + ext);
          formData.append("model",    "whisper-large-v3");
          formData.append("language", language?.code || "en");

          const res  = await fetch(GROQ_STT_URL, {
            method: "POST",
            headers: { Authorization: "Bearer " + GROQ_API_KEY },
            body: formData,
          });
          const json = await res.json();
          const text = json?.text?.trim();

          if (text) {
            sendToAria(text);
          } else {
            ariaStatusRef.current = "idle"; setAriaStatus("idle");
          }
        } catch (err) {
          console.error("STT error:", err);
          setMicError("Transcription failed. Try again or type below.");
          ariaStatusRef.current = "idle"; setAriaStatus("idle");
        }
      };

      recorder.start(250);
      setListening(true);
      setAriaStatus("listening");
      setMicError("");
    } catch (err) {
      console.error("MediaRecorder error:", err);
      listeningRef.current  = false;
      ariaStatusRef.current = "idle";
      setListening(false);
      setAriaStatus("idle");
    }
  }

  // ── END CALL ───────────────────────────────────────────────────────────────
  function endCall() {
    const msgs = messagesRef.current;
    if (msgs.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(msgs));
      setSavedConvo(msgs);
    }
    cleanupCall();
    setCallActive(false);
    setAriaStatus("idle");
    setListening(false);
    setMicError("");
  }

  // ── MANUAL MIC TOGGLE ─────────────────────────────────────────────────────
  function toggleMic() {
    if (ariaStatusRef.current === "thinking") return;
    if (listeningRef.current) {
      // Manual early stop
      listeningRef.current = false;
      if (mediaRecRef.current && mediaRecRef.current.state === "recording") {
        mediaRecRef.current.stop();
      }
    } else {
      synthRef.current.cancel();
      ariaStatusRef.current = "idle";
      beginRecording();
    }
  }

  // ── SEND TO GROQ LLM ──────────────────────────────────────────────────────
  async function sendToAria(text) {
    const history = messagesRef.current.map(m => ({
      role:    m.role === "aria" ? "assistant" : "user",
      content: m.text,
    }));

    setMessages(prev => [...prev, { role: "user", text }]);
    ariaStatusRef.current = "thinking";
    setAriaStatus("thinking");
    setLoading(true);

    try {
      const res = await fetch(GROQ_CHAT_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: "Bearer " + GROQ_API_KEY },
        body: JSON.stringify({
          model: "llama-3.3-70b-versatile",
          messages: [
            {
              role: "system",
              content: "You are Aria, a friendly conversational language tutor.\nTopic: " + topic + ". Student is learning: " + (language?.name || "a language") + ".\nRules:\n- Always give a COMPLETE, full sentence response. Never cut off mid-sentence.\n- Respond in 2-4 complete sentences.\n- Respond in " + (language?.name || "the target language") + " with English hints in [brackets] only when needed.\n- Gently correct errors inline without stopping the conversation.\n- Always finish your thought completely before stopping.\n- Never go off topic.",
            },
            ...history,
            { role: "user", content: text },
          ],
          max_tokens: 500,
          temperature: 0.7,
        }),
      });

      const data  = await res.json();
      const reply = data?.choices?.[0]?.message?.content || "Sorry, I did not catch that.";
      setMessages(prev => [...prev, { role: "aria", text: reply }]);
      speakAria(reply);
    } catch (err) {
      setMessages(prev => [...prev, { role: "aria", text: "Sorry, something went wrong." }]);
      ariaStatusRef.current = "idle"; setAriaStatus("idle");
    }
    setLoading(false);
  }

  // ── TTS ───────────────────────────────────────────────────────────────────
  function speakAria(text) {
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang  = getLangCode(language?.code);
    utterance.rate  = 0.88;
    utterance.pitch = 1.05;
    speakStartRef.current = Date.now();
    ariaStatusRef.current = "speaking";
    setAriaStatus("speaking");
    utterance.onend = () => {
      if (ariaStatusRef.current === "speaking") {
        ariaStatusRef.current = "idle";
        setAriaStatus("idle");
        // Wait POST_SPEAK_DELAY ms so speaker echo dies down before mic starts listening
        setTimeout(() => beginRecording(), POST_SPEAK_DELAY);
      }
    };
    synthRef.current.speak(utterance);
  }

  function sendTextMessage() {
    if (!textInput.trim() || loading) return;
    const text = textInput.trim();
    setTextInput("");
    sendToAria(text);
  }

  const statusLabel = {
    idle:      "Listening for your voice...",
    listening: "🔴 Recording... speak fully, sends after 3s silence",
    thinking:  "💭 Aria is thinking...",
    speaking:  "🔊 Aria is speaking... (talk to interrupt)",
  }[ariaStatus] || "Listening for your voice...";

  return (
    <div className="call-container">
      {!callActive ? (
        <div className="call-idle">
          <div className="call-avatar">🤖</div>
          <p className="call-aria-name">Aria</p>
          <p className="call-topic">Topic: <strong>{topic}</strong></p>
          <p className="call-lang">Language: <strong>{language?.name}</strong></p>
          {micError && <p className="call-mic-error">{micError}</p>}
          <button className="call-start-btn" onClick={() => startCall()}>
            📞 Start Call
          </button>
          {savedConvo && savedConvo.length > 0 && (
            <button className="call-resume-btn" onClick={() => startCall(savedConvo)}>
              🔁 Resume Last Conversation
              <span className="call-resume-count">{savedConvo.length} messages</span>
            </button>
          )}
        </div>
      ) : (
        <div className="call-active">
          <div className="call-messages">
            {messages.map((msg, i) => (
              <div key={i} className={"call-bubble " + msg.role}>
                {msg.role === "aria" && <span className="call-name">Aria</span>}
                <p>{msg.text}</p>
              </div>
            ))}
            {ariaStatus === "thinking" && (
              <div className="call-bubble aria">
                <span className="call-name">Aria</span>
                <p className="typing">● ● ●</p>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="call-controls">
            <p className="call-status">{statusLabel}</p>
            {micError && <p className="call-mic-error">{micError}</p>}
            <button
              className={"call-mic-btn" + (listening ? " active" : "")}
              onClick={toggleMic}
              disabled={ariaStatus === "thinking"}
            >
              {listening ? "🔴" : "🎙"}
            </button>
            <button className="call-end-btn" onClick={endCall}>📵 End Call</button>
          </div>

          <div className="chat-input-row">
            <input
              className="chat-input"
              value={textInput}
              onChange={(e) => setTextInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && sendTextMessage()}
              placeholder="Or type your message..."
              disabled={loading}
            />
            <button className="chat-send" onClick={sendTextMessage}>➤</button>
          </div>
        </div>
      )}
    </div>
  );
}
